/**
 * Strip the query string and fragment from a presigned URL before logging.
 *
 * AWS-style presigned URLs carry the signature, expiry, and credential scope
 * in the query string — together they form a bearer credential for the
 * uploaded payload. Logs that include the full URL leak that credential to
 * anything that captures stdout/stderr (customer logs, notebooks, support
 * bundles, CI). Strip the query and fragment; keep scheme/host/path so the
 * log entry is still useful for debugging.
 *
 * Mirrors Python `_redact_presigned_url` in
 * `_internal/big_payloads/core.py:114-130`.
 */
export function redactPresignedUrl(url: string): string {
  if (!url) return url
  try {
    const u = new URL(url)
    u.search = ''
    u.hash = ''
    return u.toString()
  } catch {
    return '<unparseable-url>'
  }
}
