/**
 * Response-side `$ref` envelope unwrap — TypeScript port of Python SDK
 * `_internal/big_payloads/core.py::_resolve_response_envelope` / `_finalize`
 * (Python 0.4.9).
 *
 * Symmetric with the request side: when a service responds with a body that is
 * exactly `{"$ref": "<https url>"}` on a 2xx, the gateway has stashed the real
 * (large) JSON response in S3. This module transparently fetches it:
 *
 *   1. Validate the URL is https (the presigned URL is a bearer credential).
 *   2. Preflight `Range: bytes=0-0` GET — fail fast on auth/size before the
 *      full download (no auth headers; the URL is self-authenticating).
 *   3. Full GET, capped at `RESPONSE_MAX_BYTES`.
 *   4. Unzip the single `payload.json` entry, UTF-8 decode, JSON.parse.
 *
 * Errors map to `BigPayloadFetchError` with the cross-repo `REF_*` codes so
 * callers can dispatch on `.code` without parsing messages. Non-envelope
 * bodies pass through untouched (this is a no-op for the common case).
 */

import { unzipSync } from 'fflate'
import { BigPayloadFetchError } from '../../errors'
import {
  RESPONSE_FETCH_TIMEOUT_MS,
  RESPONSE_MAX_BYTES,
  RESPONSE_PREFLIGHT_TIMEOUT_MS,
} from './constants'
import { redactPresignedUrl } from './redact'

/** The single zip entry name — part of the cross-repo contract (gateway /
 * lambda-models write the inner JSON under this exact name). */
const PAYLOAD_ENTRY = 'payload.json'

/**
 * Detect a response-side `$ref` envelope. Returns the URL only if the body is
 * exactly `{"$ref": "<https url with a host>"}` — strict single key, https
 * scheme, non-empty host. Mirrors Python's `_is_response_envelope_body`, which
 * validates scheme + netloc at detection time and returns `None` otherwise so
 * a non-envelope `$ref`-shaped body PASSES THROUGH to the caller untouched
 * (rather than raising). Anything that isn't a clean https envelope → `null`.
 */
export function detectResponseRef(body: unknown): string | null {
  if (!body || typeof body !== 'object' || Array.isArray(body)) return null
  const keys = Object.keys(body as Record<string, unknown>)
  if (keys.length !== 1 || keys[0] !== '$ref') return null
  const url = (body as Record<string, unknown>).$ref
  if (typeof url !== 'string' || url.length === 0) return null
  try {
    const u = new URL(url)
    if (u.protocol !== 'https:' || !u.host) return null
  } catch {
    return null // unparseable → not an envelope, pass through (Python parity)
  }
  return url
}

/**
 * Resolve a response body: if it is a `$ref` envelope, fetch + unzip + parse
 * the referenced JSON; otherwise return the body unchanged.
 */
export async function resolveResponseRef(
  body: unknown,
  opts: { signal?: AbortSignal } = {},
): Promise<unknown> {
  const url = detectResponseRef(body)
  if (url === null) return body // not a (valid https) envelope → pass through

  // `url` is guaranteed an https URL with a host by detectResponseRef (the
  // presigned URL carries SigV4 credentials in its query, hence https-only).
  const redacted = redactPresignedUrl(url)

  // Preflight: read headers + total size cheaply before the full download.
  await preflight(url, redacted, opts.signal)

  // Full GET (no auth — presigned URL is self-authenticating).
  const bytes = await fetchFull(url, redacted, opts.signal)

  return decodeInner(bytes, redacted)
}

async function preflight(url: string, redacted: string, signal?: AbortSignal): Promise<void> {
  const resp = await getNoAuth(
    url,
    { Range: 'bytes=0-0' },
    RESPONSE_PREFLIGHT_TIMEOUT_MS,
    redacted,
    signal,
  )
  checkStatus(resp, redacted)
  checkContentType(resp, redacted)

  // S3 reports the full object size in `Content-Range: bytes 0-0/<total>`.
  const contentRange = resp.headers.get('Content-Range')
  if (contentRange) {
    const m = contentRange.match(/\/\s*(\d+)\s*$/)
    if (m && Number(m[1]) > RESPONSE_MAX_BYTES) {
      throw new BigPayloadFetchError(
        'REF_TOO_LARGE',
        `response $ref body ${m[1]}B exceeds ${RESPONSE_MAX_BYTES}B cap: ${redacted}`,
        { statusCode: resp.status },
      )
    }
  }
  await drain(resp)
}

async function fetchFull(url: string, redacted: string, signal?: AbortSignal): Promise<Uint8Array> {
  const resp = await getNoAuth(url, {}, RESPONSE_FETCH_TIMEOUT_MS, redacted, signal)
  checkStatus(resp, redacted)
  checkContentType(resp, redacted)

  // Declared size guard (cheap) before reading the body into memory.
  const contentLength = resp.headers.get('Content-Length')
  if (contentLength && Number(contentLength) > RESPONSE_MAX_BYTES) {
    throw new BigPayloadFetchError(
      'REF_TOO_LARGE',
      `response $ref body ${contentLength}B exceeds ${RESPONSE_MAX_BYTES}B cap: ${redacted}`,
      { statusCode: resp.status },
    )
  }

  let buf: ArrayBuffer
  try {
    buf = await resp.arrayBuffer()
  } catch (err) {
    throw new BigPayloadFetchError(
      'REF_FETCH_TIMEOUT',
      `response $ref body read failed: ${redacted} (${errMsg(err)})`,
      { statusCode: resp.status },
    )
  }
  if (buf.byteLength > RESPONSE_MAX_BYTES) {
    throw new BigPayloadFetchError(
      'REF_TOO_LARGE',
      `response $ref body ${buf.byteLength}B exceeds ${RESPONSE_MAX_BYTES}B cap: ${redacted}`,
      { statusCode: resp.status },
    )
  }
  return new Uint8Array(buf)
}

/** Unzip the single `payload.json` entry → UTF-8 → JSON. */
function decodeInner(zipBytes: Uint8Array, redacted: string): unknown {
  let files: Record<string, Uint8Array>
  try {
    files = unzipSync(zipBytes)
  } catch (err) {
    throw new BigPayloadFetchError(
      'REF_DECODE_FAILED',
      `response $ref unzip failed: ${redacted} (${errMsg(err)})`,
    )
  }
  // Prefer the contract entry; else the first NON-directory entry (mirrors
  // Python's `infolist()` + `is_dir()` skip — fflate keys directory markers
  // with a trailing '/' and a zero-length body).
  const firstFile = Object.keys(files).find((k) => !k.endsWith('/'))
  const inner = files[PAYLOAD_ENTRY] ?? (firstFile ? files[firstFile] : undefined)
  if (!inner) {
    throw new BigPayloadFetchError(
      'REF_DECODE_FAILED',
      `response $ref archive has no non-directory entries: ${redacted}`,
    )
  }
  // Bound the DECOMPRESSED payload too — the compressed-size cap in fetchFull
  // doesn't stop a high-ratio zip. NOTE: fflate's `unzipSync` inflates the
  // whole entry before this check, so this caps the returned payload but not
  // the transient allocation; a true streaming pre-decompress guard (Python
  // checks ZipInfo.file_size first) is a follow-up.
  if (inner.byteLength > RESPONSE_MAX_BYTES) {
    throw new BigPayloadFetchError(
      'REF_TOO_LARGE',
      `response $ref decompressed payload ${inner.byteLength}B exceeds ${RESPONSE_MAX_BYTES}B cap: ${redacted}`,
    )
  }
  let text: string
  try {
    text = new TextDecoder('utf-8', { fatal: true }).decode(inner)
  } catch (err) {
    throw new BigPayloadFetchError(
      'REF_DECODE_FAILED',
      `response $ref inner payload is not valid UTF-8: ${redacted} (${errMsg(err)})`,
    )
  }
  try {
    return JSON.parse(text)
  } catch (err) {
    throw new BigPayloadFetchError(
      'REF_DECODE_FAILED',
      `response $ref inner payload is not valid JSON: ${redacted} (${errMsg(err)})`,
    )
  }
}

// ---------------------------------------------------------------------------
// HTTP helpers (no-auth GET with timeout + external-signal chaining)
// ---------------------------------------------------------------------------

async function getNoAuth(
  url: string,
  headers: Record<string, string>,
  timeoutMs: number,
  redacted: string,
  signal?: AbortSignal,
): Promise<Response> {
  const controller = new AbortController()
  const timeoutId = setTimeout(() => controller.abort(), timeoutMs)

  let externalAbortHandler: (() => void) | undefined
  if (signal) {
    if (signal.aborted) {
      clearTimeout(timeoutId)
      const e = new Error('Request aborted by external signal')
      e.name = 'AbortError'
      throw e
    }
    externalAbortHandler = () => controller.abort()
    signal.addEventListener('abort', externalAbortHandler, { once: true })
  }

  try {
    // `redirect: 'error'` mirrors Python's `allow_redirects=False`: a SigV4
    // signature binds to the original host, and following a redirect could
    // leak the presigned credential to another origin.
    return await fetch(url, { method: 'GET', headers, redirect: 'error', signal: controller.signal })
  } catch (err) {
    if (signal?.aborted) throw err
    throw new BigPayloadFetchError(
      'REF_FETCH_TIMEOUT',
      `response $ref GET failed/timed out: ${redacted} (${errMsg(err)})`,
    )
  } finally {
    clearTimeout(timeoutId)
    if (signal && externalAbortHandler) {
      signal.removeEventListener('abort', externalAbortHandler)
    }
  }
}

function checkStatus(resp: Response, redacted: string): void {
  if (resp.ok) return
  if (resp.status === 401 || resp.status === 403) {
    throw new BigPayloadFetchError(
      'REF_EXPIRED',
      `response $ref GET unauthorized/expired (${resp.status}): ${redacted}`,
      { statusCode: resp.status },
    )
  }
  throw new BigPayloadFetchError(
    'REF_NOT_FOUND',
    `response $ref GET failed (${resp.status}): ${redacted}`,
    { statusCode: resp.status },
  )
}

function checkContentType(resp: Response, redacted: string): void {
  // Strict, matching Python `_check_get_content_type`: the primary media type
  // must be exactly `application/zip` (charset/boundary params tolerated, case
  // insensitive). A MISSING/empty header is rejected too — an upstream error
  // page (HTML / S3 XML) with the header stripped must surface as a clear
  // REF_CONTENT_TYPE_REJECTED, not a confusing REF_DECODE_FAILED from unzip.
  const ct = resp.headers.get('Content-Type')
  const primary = (ct ?? '').split(';', 1)[0].trim().toLowerCase()
  if (primary !== 'application/zip') {
    throw new BigPayloadFetchError(
      'REF_CONTENT_TYPE_REJECTED',
      `response $ref Content-Type ${JSON.stringify(ct)} is not application/zip: ${redacted}`,
      { statusCode: resp.status },
    )
  }
}

async function drain(resp: Response): Promise<void> {
  try {
    await resp.arrayBuffer()
  } catch {
    // best-effort — releasing the body is not load-bearing here
  }
}

function errMsg(err: unknown): string {
  return err instanceof Error ? err.message : String(err)
}
