/**
 * Constants for the auto-switching big-payload POST flow.
 * Mirror Python SDK's `_internal/big_payloads/core.py:55-73`.
 *
 * These are wire-contract values shared with the gateway and
 * `lambda-models`. Producers and gateway must agree on the threshold to
 * keep behaviour predictable across versions.
 */

/** Default cut-over threshold (5 MB raw JSON, pre-zip). Strict greater-than:
 * payloads at or below this size go inline. */
export const THRESHOLD_DEFAULT_BYTES = 5 * 1024 * 1024

/**
 * Presign call timeout (ms). Mirrors Python's `(connect=10, read=30)` —
 * native `fetch` only supports one overall AbortController timeout, so we
 * collapse to the read budget.
 */
export const PRESIGN_TIMEOUT_MS = 30_000

/**
 * S3 PUT timeout (ms). Mirrors Python's `(connect=10, read=600)`. Multi-MB
 * zips can take tens of seconds on cold S3 paths; share the same ceiling
 * customers see for S3 GET in the existing job-results download flow.
 */
export const S3_PUT_TIMEOUT_MS = 600_000

/** Max retries when the receiving service responds `REF_EXPIRED`. Each
 * retry re-presigns and re-uploads the same zip bytes. */
export const MAX_REF_EXPIRED_RETRIES = 2

/** Max retries when the S3 PUT itself fails with a transient 5xx. The
 * presigned URL is reused (same bytes → same signature). 4xx is not
 * retried. */
export const MAX_PUT_RETRIES = 2

/** Allowed URL schemes for the `upload-url`/`get-url` strings returned by
 * the gateway. HTTPS only — the URLs are bearer credentials and an http://
 * downgrade would expose the payload to interception. */
export const ALLOWED_PRESIGNED_SCHEMES = ['https:'] as const

/** Env var names. Read on every call (not at import time) so notebook
 * users can flip the kill switch mid-session. */
export const ENV_ENABLED = 'INFRARED_BIG_PAYLOADS_ENABLED'
export const ENV_THRESHOLD = 'INFRARED_BIG_PAYLOADS_THRESHOLD_BYTES'

// ---------------------------------------------------------------------------
// Response-side `$ref` envelope unwrap (Python 0.4.9 parity).
// When a 2xx response body is itself `{"$ref": "<https url>"}`, the SDK
// transparently fetches the presigned S3 object, unzips the single
// `payload.json` entry, and returns the inner JSON. Mirrors Python
// `_resolve_response_envelope` in `_internal/big_payloads/core.py`.
// ---------------------------------------------------------------------------

/** Hard cap on a `$ref` response payload (250 MiB). Enforced on the COMPRESSED
 * download (preflight `Content-Range` total, `Content-Length`, and the read
 * byte count) and on the DECOMPRESSED payload (post-unzip byte length). A
 * streaming pre-decompress guard against high-ratio zip bombs (Python checks
 * `ZipInfo.file_size` before reading) is a documented follow-up. Mirrors
 * Python's cap value. */
export const RESPONSE_MAX_BYTES = 250 * 1024 * 1024

/** Preflight `Range: bytes=0-0` GET timeout (ms) — fails fast on size/auth
 * before committing to the full download. Mirrors Python's connect/read split
 * collapsed to one fetch budget. */
export const RESPONSE_PREFLIGHT_TIMEOUT_MS = 30_000

/** Full `$ref` GET timeout (ms). Large results can take tens of seconds on a
 * cold S3 path — same ceiling as the S3 PUT / job-results download. */
export const RESPONSE_FETCH_TIMEOUT_MS = 600_000
